bool CheckHex(const std::string& str) {
    size_t data=0;
    if(str.size() > 2 && (str.compare(0, 2, "0x") == 0 || str.compare(0, 2, "0X") == 0)){
        data=2;
    }
    return str.size() > data && str.find_first_not_of("0123456789abcdefABCDEF", data) == std::string::npos;
}

