namespace FmPmd {

	In_Module module = {
		IN_VER,
		PLUGIN_DETAIL,
		0,	/* hMainWindow (filled in by winamp after init() ) */
		0,  /* hDllInstance ( Also filled in by winamp) */
		NULL, // FileExtensions handled by this DLL

